use thiserror::Error;

#[derive(Error, Debug)]
pub enum ServiceError {
    #[error("not found: {0}")]
    NotFound(String),
    #[error("io error")]
    Io(#[from] std::io::Error),
}

pub fn load_config(path: &Path) -> Result<Config, ServiceError> {
    let content = std::fs::read_to_string(path)?;
    toml::from_str(&content).map_err(|e| ServiceError::Parse(e.to_string()))
}
